INSERT INTO guia.dbo.SignosZodiacales (Nombre,Icono,Elemento,DescripcionLarga,PalabrasClave) VALUES
	 (N'Aries',N'♈',N'Fuego',N'Es el despertar de la vida. Representa la energía impulsiva, el liderazgo natural y el coraje para iniciar nuevos ciclos. Su fuerza es la acción pura.',N'Iniciativa, Valor, Energía'),
	 (N'Tauro',N'♉',N'Tierra',N'La estabilidad hecha materia. Representa la perseverancia, el disfrute de los sentidos y la capacidad de dar forma y permanencia a los proyectos.',N'Resistencia, Bienestar, Firmeza'),
	 (N'Géminis',N'♊',N'Aire',N'El puente de la comunicación. Representa la dualidad, el intelecto curioso y la capacidad de adaptar el pensamiento a múltiples realidades.',N'Dualidad, Mente, Adaptabilidad'),
	 (N'Cáncer',N'♋',N'Agua',N'El refugio del alma. Rige las emociones profundas, la nutrición espiritual y los lazos con el origen y la familia. Su fuerza es la intuición.',N'Emoción, Protección, Raíces'),
	 (N'Leo',N'♌',N'Fuego',N'El centro radiante. Representa la creatividad, la autoexpresión digna y el poder del corazón. Es el brillo soberano que inspira a otros.',N'Brillo, Generosidad, Creatividad'),
	 (N'Virgo',N'♍',N'Tierra',N'La alquimia del detalle. Busca la perfección a través del servicio, el análisis y la purificación de la materia y el espíritu.',N'Análisis, Orden, Servicio'),
	 (N'Libra',N'♎',N'Aire',N'La armonía del encuentro. Representa la justicia, la belleza en las relaciones y la búsqueda constante del equilibrio entre los opuestos.',N'Equilibrio, Justicia, Unión'),
	 (N'Escorpio',N'♏',N'Agua',N'La transformación profunda. Rige los misterios, la muerte y el renacimiento. Su energía es magnética, intensa y regeneradora.',N'Transmutación, Poder, Intensidad'),
	 (N'Sagitario',N'♐',N'Fuego',N'La flecha de la verdad. Representa la expansión de la conciencia, los viajes largos y la búsqueda filosófica del sentido de la vida.',N'Expansión, Optimismo, Libertad'),
	 (N'Capricornio',N'♑',N'Tierra',N'La cima del logro. Representa la disciplina, el tiempo y la construcción de un legado sólido a través del esfuerzo y la maestría.',N'Estructura, Ambición, Maestría');
INSERT INTO guia.dbo.SignosZodiacales (Nombre,Icono,Elemento,DescripcionLarga,PalabrasClave) VALUES
	 (N'Acuario',N'♒',N'Aire',N'El visionario del futuro. Representa la libertad individual, la innovación social y la conexión con la mente universal y colectiva.',N'Innovación, Humanismo, Desapego'),
	 (N'Piscis',N'♓',N'Agua',N'El océano de la unidad. Representa la compasión universal, los sueños y la disolución del ego para conectar con el todo espiritual.',N'Misticismo, Compasión, Sueños');
